96669,0.00553921,0.03010924,0.04037892,0.00508540,-0.02624624,0.12199023,0.05398846,0.03721361,0.00142091,0.06047508,0.00434045,0.03913190,-0.04687494,-0.00399910,-0.03382738,-0.03396431,-0.06184188,-0.04277278,0.03743145,0.00510265,0.03641355,0.04374905,-0.05137640,-0.02363835,-0.03906856,-0.03879716,-0.02179730,-0.03678196,-0.02725614,-0.01174378,-0.03639737,0.01843181,0.03593232,0.04454717,0.00298226,-0.02610127,0.01292695,0.00391132,-0.03596054,0.10767484,-0.02332355,0.04660585]',E'Quickstart\n\n```go\nimport (\n    "context"\n    "fmt"\n\n    "github.com/redis/go-redis/v9"\n)\n\nvar ctx = context.Background()\n\nfunc ExampleClient() {\n    rdb := redis.NewClient(&redis.Options{\n        Addr:     "localhost:6379",\n        Password: "", // no password set\n        DB:       0,  // use default DB\n    })\n    defer rdb.Close()\n\n    err := rdb.Set(ctx, "key", "value", 0).Err()\n    if err != nil {\n        panic(err)\n    }\n\n    val, err := rdb.Get(ctx, "key").Result()\n    if err != nil {\n        panic(err)\n    }\n    fmt.Println("key", val)\n\n    val2, err := rdb.Get(ctx, "key2").Result()\n    if err == redis.Nil {\n        fmt.Println("key2 does not exist")\n    } else if err != nil {\n        panic(err)\n    } else {\n        fmt.Println("key2", val2)\n    }\n    // Output: key value\n    // key2 does not exist\n}\n```','{"source": "redis", "version": "7", "language": "go", "title": "Redis client for Go", "section_title": "README", "url": "https://github.com/redis/go-redis/blob/master/README.md", "topics": "redis,go,cache,README", "categories": "database,cache,go"}');
