.16539253,0.03731374,-0.02965823,0.00134508,0.00610993,-0.02780558,0.06881300,0.07676365,0.03212351,-0.02310927,0.04062056,0.02661336,0.04396231,0.01362752,-0.00672521,0.01904357,0.00216206,-0.00876687,-0.02124941,0.01984928,-0.03885884,0.04471564,0.04945072,-0.03511022,-0.02102707,-0.02017019,-0.00175332,-0.01262001,-0.06711145,-0.02555380,-0.00287376,-0.04566993,0.00590919,-0.00089959,0.02398267,-0.00996620,-0.02417998,0.01080705,0.00880796,-0.08535849,0.06310847,-0.01599664,-0.01157163]',E'Look and feel\n\nSome corner cases:\n\n```go\n// SET key value EX 10 NX\nset, err := rdb.SetNX(ctx, "key", "value", 10*time.Second).Result()\n\n// SET key value keepttl NX\nset, err := rdb.SetNX(ctx, "key", "value", redis.KeepTTL).Result()\n\n// SORT list LIMIT 0 2 ASC\nvals, err := rdb.Sort(ctx, "list", &redis.Sort{Offset: 0, Count: 2, Order: "ASC"}).Result()\n\n// ZRANGEBYSCORE zset -inf +inf WITHSCORES LIMIT 0 2\nvals, err := rdb.ZRangeByScoreWithScores(ctx, "zset", &redis.ZRangeBy{\n    Min: "-inf",\n    Max: "+inf",\n    Offset: 0,\n    Count: 2,\n}).Result()\n\n// ZINTERSTORE out 2 zset1 zset2 WEIGHTS 2 3 AGGREGATE SUM\nvals, err := rdb.ZInterStore(ctx, "out", &redis.ZStore{\n    Keys: []string{"zset1", "zset2"},\n    Weights: []int64{2, 3}\n}).Result()\n\n// EVAL "return {KEYS[1],ARGV[1]}" 1 "key" "hello"\nvals, err := rdb.Eval(ctx, "return {KEYS[1],ARGV[1]}", []string{"key"}, "hello").Result()\n\n// custom command\nres, err := rdb.Do(ctx, "set", "key", "value").Result()\n```','{"source": "redis", "version": "7", "language": "go", "title": "Redis client for Go", "section_title": "README", "url": "https://github.com/redis/go-redis/blob/master/README.md", "topics": "redis,go,cache,README", "categories": "database,cache,go"}');
